args.sparql:
SELECT ?premier ?premierLabel WHERE {
  ?office wdt:P31 wd:Q2641671 ;
          rdfs:label 'Premier of the Northern Cape'@en ;
          wdt:P131 wd:Q32184 .
  ?premier wdt:P39 ?office ;
          wdt:P580 ?start ;
          wdt:P582 ?end .
  FILTER (YEAR(?start) <= 2018 && YEAR(?end) >= 2018)
  ?premier rdfs:label ?premierLabel .
  FILTER (LANG(?premierLabel) = 'en')
}
